// ---- Coroutines Basics ----
// Dependencies:
// implementation("org.jetbrains.kotlinx:kotlinx-coroutines-android:1.7.3")

// ---- What are Coroutines? ----
// Lightweight threads that don't block the main thread

// ---- Basic coroutine ----
@Composable
fun CoroutineExample() {
    val scope = rememberCoroutineScope()
    var result by remember { mutableStateOf("Waiting...") }
    var isLoading by remember { mutableStateOf(false) }

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        if (isLoading) {
            CircularProgressIndicator()
        }

        Text(result, style = MaterialTheme.typography.headlineMedium)

        Button(
            onClick = {
                scope.launch {
                    isLoading = true
                    result = "Loading..."

                    // ---- Simulate network call ----
                    delay(2000)

                    result = "Done!"
                    isLoading = false
                }
            }
        ) {
            Text("Start Work")
        }
    }
}

// ---- Coroutine with ViewModel ----
class CoroutineViewModel : ViewModel() {
    private val _result = MutableStateFlow("")
    val result: StateFlow<String> = _result.asStateFlow()

    fun doWork() {
        viewModelScope.launch {
            _result.value = "Working..."
            delay(2000)
            _result.value = "Work completed!"
        }
    }

    // ---- Sequential coroutines ----
    fun doSequentialWork() {
        viewModelScope.launch {
            _result.value = "Step 1..."
            delay(1000)

            _result.value = "Step 2..."
            delay(1000)

            _result.value = "Step 3..."
            delay(1000)

            _result.value = "All steps complete!"
        }
    }

    // ---- Parallel coroutines ----
    fun doParallelWork() {
        viewModelScope.launch {
            val result1 = async { heavyWork(1) }
            val result2 = async { heavyWork(2) }
            val result3 = async { heavyWork(3) }

            val combined = listOf(result1.await(), result2.await(), result3.await())
            _result.value = combined.joinToString(", ")
        }
    }

    private suspend fun heavyWork(id: Int): String {
        delay(1000)
        return "Result from $id"
    }
}

// ---- Coroutine with error handling ----
class ErrorHandlingViewModel : ViewModel() {
    private val _state = MutableStateFlow("Idle")
    val state: StateFlow<String> = _state.asStateFlow()

    fun doRiskyWork() {
        viewModelScope.launch {
            try {
                _state.value = "Loading..."

                // Simulate risky operation
                val result = riskyOperation()

                _state.value = "Success: $result"
            } catch (e: Exception) {
                _state.value = "Error: ${e.message}"
            }
        }
    }

    private suspend fun riskyOperation(): String {
        delay(1000)
        if (System.currentTimeMillis() % 2 == 0L) {
            throw Exception("Something went wrong!")
        }
        return "Success!"
    }
}

// ---- Dispatchers ----
class DispatcherViewModel : ViewModel() {
    private val _state = MutableStateFlow("")
    val state: StateFlow<String> = _state.asStateFlow()

    fun doWork() {
        viewModelScope.launch(Dispatchers.IO) {
            // Network, database, file I/O
            _state.value = "Working on IO thread"
            delay(1000)

            withContext(Dispatchers.Main) {
                // Update UI
                _state.value = "Done on Main thread"
            }
        }
    }
}

