class BrokenCoroutines : ViewModel() {
    // 1. Not using viewModelScope
    fun doWork() {
        GlobalScope.launch {  // Memory leak!
            delay(1000)
        }
    }

    // 2. Blocking on main thread
    fun doHeavyWork() {
        Thread.sleep(5000)  // Blocks UI!
    }

    // 3. Not handling exceptions
    fun doRiskyWork() {
        viewModelScope.launch {
            throw Exception()  // Crash!
        }
    }
}

@Composable
fun BrokenCoroutineUI() {
    // 4. Not using rememberCoroutineScope
    val scope = CoroutineScope(Dispatchers.Main)
    // Wrong scope, no lifecycle awareness
}

phase2.explanation:
🤖 **Common coroutine mistakes and fixes.**

| Mistake | Fix |
|---------|-----|
| GlobalScope | Use `viewModelScope` |
| Thread.sleep | Use `delay` |
| No exception handling | Use `try-catch` |
| Wrong scope | Use `rememberCoroutineScope` |

**Fixes:**
```kotlin
// 1. Use viewModelScope
viewModelScope.launch { /* work */ }

// 2. Use delay
suspend fun doWork() {
    delay(1000)
}

// 3. Handle exceptions
try {
    // risky work
} catch (e: Exception) {
    // handle error
}

// 4. Use rememberCoroutineScope
val scope = rememberCoroutineScope()
```

